+fn native_stream_open_flags(open_flags: OpenFlags) -> u32 {
+    let mut flags = 0u32;
+    if open_flags.readable {
+        flags |= io_internal_abi::file_flags::READ;
+    }
+    if open_flags.writable {
+        flags |= io_internal_abi::file_flags::WRITE;
+    }
+    if open_flags.append {
